let messageGlobal = 'Je suis partout';

function maFonction() {
  let messageLocal = 'Je suis privé';
  console.log(messageGlobal);  // OK : variable globale
  console.log(messageLocal);   // OK : déclarée ici
}

maFonction();
// console.log(messageLocal); // ERREUR : hors portée

// Les blocs {} créent une portée avec let/const
if (true) {
  let bloqueIci = 'visible seulement dans ce bloc';
  const aussiBloques = true;
}
// console.log(bloqueIci); // ERREUR

// var (ancien) : pas de portée de bloc — à éviter
if (true) {
  var fuiteVar = 'je fuis hors du bloc !';
}
console.log(fuiteVar); // 'je fuis hors du bloc !' (comportement surprenant)
